  // Función para enviar el pedido

  const enviarPedido = async () => {
    try {
      setEnviando(true);
      setMensajeExito("");
      setErrorCuenta("");

      if (!cuenta) {
        setMensajeExito("Error: cuenta no cargada. Intente nuevamente.");
        setEnviando(false);
        return;
      }

      // saldo pendiente
      if (cuenta.tiene_saldo_pendiente && cuenta.bloquear_por_saldo) {
        const { data: docsPendientes, error: docsError } = await supabase
          .from("documentos_pendientes")
          .select("*")
          .eq("cuenta_id", cuenta.id)
          .eq("pagado", false);

        if (!docsError && docsPendientes && docsPendientes.length > 0) {
          setDocumentosPendientesModal(docsPendientes);
          setMostrarModalSaldoPendiente(true);
          setMostrarModalPedido(false);
          setEnviando(false);
          return;
        }
      }

      // Formato: CODIGO*CANTIDAD-CODIGO*CANTIDAD
      const listaProductosString = carrito
        .map((p) => `${p.CODIGO}*${p.cantidad}`)
        .join("-");

      // Calcular el total
      const total = carrito.reduce(
        (sum, p) =>
          sum + (p.subtotal ?? (p.cantidad ?? 0) * (p.P_MAYOREO ?? 0)),
        0,
      );

      // Calcular subtotal (sin IVA), IVA y total
      const subtotalSinIVA = total / 1.08;
      const iva = total - subtotalSinIVA;
      const totalConIVA = total;

      // Guardar pedido en Supabase
      const { data: pedidoInsertado, error: errorPedido } = await supabase
        .from("pedidos")
        .insert([
          {
            cuenta_id: cuenta.id,
            total: total,
            estado: "nuevo_pedido",
            es_domicilio: enviarDomicilio,
            lista_productos: listaProductosString,
          },
        ])
        .select()
        .single();

      if (errorPedido) {
        console.error("Error registrando pedido:", errorPedido);
      } else {
        console.log("Pedido registrado");
      }

      const jsPDFModule = await import("jspdf");
      const autoTableModule = await import("jspdf-autotable");
      const QRCodeModule = await import("qrcode");
      const { jsPDF } = jsPDFModule;

      const pedidoId = pedidoInsertado.id;
      const numeroCotizacion = pedidoId;
      const fecha = new Date().toLocaleDateString("es-MX", {
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
      });
      const hora = new Date().toLocaleTimeString("es-MX");

     

      // Cargar logo como base64
      const getImageBase64 = async (url: string): Promise<string> => {
        const response = await fetch(url);
        const blob = await response.blob();
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.onerror = reject;
          reader.readAsDataURL(blob);
        });
      };

      const logoBase64 = await getImageBase64("/logo-pdf.png");
      // Función para dibujar el encabezado DEL PDF DE ENVÍO (con tipo de documento)
      const dibujarEncabezadoEnvio = (doc: any) => {
        const pageWidth = doc.internal.pageSize.width;
        const ahora = new Date();
        const horaActual = ahora.getHours();
        let promesaEntrega = "";

        const entregaMismoDia = cuenta?.entrega_mismo_dia;

        if (enviarDomicilio) {
          if (entregaMismoDia) {
            promesaEntrega =
              horaActual < 10
                ? "Entrega: Hoy mismo"
                : "Entrega: Siguiente día hábil";
          } else {
            promesaEntrega = "Entrega: 1 a 3 días hábiles";
          }
        } else {
          promesaEntrega =
            horaActual < 15
              ? "Listo para recoger: en 3 horas"
              : "Listo para recoger: Mañana 11:00 AM";
        }

        const tipoDoc =
          cuenta?.tipo_comprobante === "Factura" ? "FACTURA" : "NOTA";

        // Logo
        doc.addImage(logoBase64, "PNG", 14, 14, 50, 15);

        // Información empresa
        doc.setFontSize(7);
        doc.setFont("helvetica", "bold");
        doc.text("SARA DEL PILAR GUZMAN GALINDO", 70, 10);
        doc.setFont("helvetica", "normal");
        doc.text("GUGS701012E14", 70, 14);
        doc.text("Av. del maestro # 24 - Col. Praxedis Balboa", 70, 18);
        doc.text("H. Matamoros, Tamaulipas, MÉXICO. CP 87430", 70, 22);
        doc.text("Tel 8682724481 | bodegaferreterademty@hotmail.com", 70, 26);

        // Folio y Fecha
        doc.setFontSize(9);
        doc.setFont("helvetica", "bold");
        doc.text("Pedido", 165, 10);
        doc.setFontSize(10);
        doc.text(numeroCotizacion.toString(), 170, 16);
        doc.setFontSize(9);
        doc.text("Fecha", 172, 24);
        doc.setFontSize(8);
        doc.setFont("helvetica", "normal");
        doc.text(fecha, 167, 30);

        // Línea separadora
        doc.setLineWidth(0.3);
        doc.line(14, 42, 196, 42);

        // Dibujar en el PDF (Fila RECEPTOR)
        doc.setFontSize(8);
        doc.setFont("helvetica", "bold");
        doc.text("RECEPTOR", 14, 48);

        doc.setFontSize(11);
        doc.setTextColor(100, 100, 100);
        doc.text(tipoDoc, pageWidth / 2, 48, { align: "center" });

        doc.setFontSize(8);
        doc.setTextColor(100, 100, 100);
        doc.text(promesaEntrega, 196, 48, { align: "right" });

        // Resetear colores para datos del cliente
        doc.setTextColor(0, 0, 0);
        doc.setFontSize(7);
        doc.setFont("helvetica", "normal");
        doc.text(`Nombre: ${cliente || cuenta?.cliente || "N/A"}`, 14, 54);
        doc.text(`Domicilio: ${cuenta?.direccion || ""}`, 14, 59);
        doc.text(`Nombre del negocio: ${cuenta?.ferreteria || ""}`, 140, 59);
        doc.text(`Tel: ${cuenta?.numero_tel || ""}`, 140, 54);
        doc.text(`Ciudad: Heroica Matamoros, Tamaulipas, México`, 14, 64);
      };

      // Función para dibujar el encabezado DEL PDF DE CLIENTE (SIN tipo de documento)
      const dibujarEncabezadoCliente = (doc: any) => {
        const pageWidth = doc.internal.pageSize.width;

        const ahora = new Date();
        const horaActual = ahora.getHours();
        let promesaEntrega = "";

        const entregaMismoDia = cuenta?.entrega_mismo_dia;

        if (enviarDomicilio) {
          if (entregaMismoDia) {
            promesaEntrega =
              horaActual < 10
                ? "Entrega: Hoy mismo"
                : "Entrega: Siguiente día hábil";
          } else {
            promesaEntrega = "Entrega: 1 a 3 días hábiles";
          }
        } else {
          promesaEntrega =
            horaActual < 15
              ? "Listo para recoger: en 3 horas"
              : "Listo para recoger: Mañana 11:00 AM";
        }

        const tipoDoc =
          cuenta?.tipo_comprobante === "Factura" ? "FACTURA" : "NOTA";

        // Logo
        doc.addImage(logoBase64, "PNG", 14, 14, 50, 15);

        // Información empresa
        doc.setFontSize(7);
        doc.setFont("helvetica", "bold");
        doc.text("SARA DEL PILAR GUZMAN GALINDO", 70, 10);
        doc.setFont("helvetica", "normal");
        doc.text("GUGS701012E14", 70, 14);
        doc.text("Av. del maestro # 24 - Col. Praxedis Balboa", 70, 18);
        doc.text("H. Matamoros, Tamaulipas, MÉXICO. CP 87430", 70, 22);
        doc.text("Tel 8682724481 | bodegaferreterademty@hotmail.com", 70, 26);

        // Folio y Fecha
        doc.setFontSize(9);
        doc.setFont("helvetica", "bold");
        doc.text("Pedido", 165, 10);
        doc.setFontSize(10);
        doc.text(numeroCotizacion.toString(), 170, 16);
        doc.setFontSize(9);
        doc.text("Fecha", 172, 24);
        doc.setFontSize(8);
        doc.setFont("helvetica", "normal");
        doc.text(fecha, 167, 30);

        // Línea separadora
        doc.setLineWidth(0.3);
        doc.line(14, 42, 196, 42);

        // RECEPTOR | PROMESA (SIN TIPO DE DOCUMENTO)
        doc.setFontSize(8);
        doc.setFont("helvetica", "bold");
        doc.text("RECEPTOR", 14, 48);

        // Resetear colores para datos del cliente
        doc.setTextColor(0, 0, 0);
        doc.setFontSize(7);
        doc.setFont("helvetica", "normal");
        doc.text(`Nombre: ${cliente || cuenta?.cliente || "N/A"}`, 14, 54);
        doc.text(`Domicilio: ${cuenta?.direccion || ""}`, 14, 59);
        doc.text(`Nombre del negocio: ${cuenta?.ferreteria || ""}`, 140, 59);
        doc.text(`Tel: ${cuenta?.numero_tel || ""}`, 140, 54);
        doc.text(`Ciudad: Heroica Matamoros, Tamaulipas, México`, 14, 64);
      };

      // PDF PARA ENVÍO (docEnvio)
      const docEnvio = new jsPDF();

      // Tabla de productos
      const productosTabla = carrito.map((p) => [
        p.CODIGO || "",
        p.cantidad,
        p.TITULO,
        `$ ${p.P_MAYOREO.toLocaleString("en-US", {
          minimumFractionDigits: 2,
          maximumFractionDigits: 2,
        })}`,
        `$ ${p.subtotal.toLocaleString("en-US", {
          minimumFractionDigits: 2,
          maximumFractionDigits: 2,
        })}`,
      ]);

      const productosTablaCliente = carrito.map((p) => [
  p.CODIGO || "",
  p.cantidad,
  p.unidad_venta || "N/A",
  p.TITULO,
  `$ ${p.P_MAYOREO.toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })}`,
  `$ ${p.subtotal.toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })}`,
]);

      autoTableModule.default(docEnvio, {
        head: [["CÓDIGO", "CANT", "DESCRIPCIÓN", "P. UNIT.", "IMPORTE"]],
        body: productosTabla,
        startY: 69,
        styles: {
          fontSize: 7,
          cellPadding: 1.5,
          lineColor: [180, 180, 180],
          lineWidth: 0.1,
          textColor: [0, 0, 0],
        },
        headStyles: {
          fillColor: [230, 230, 230],
          textColor: [0, 0, 0],
          fontStyle: "bold",
          halign: "center",
          fontSize: 7,
        },
        columnStyles: {
          0: { cellWidth: 28, halign: "center" },
          1: { cellWidth: 15, halign: "center" },
          2: { cellWidth: 82, halign: "left" },
          3: { cellWidth: 22, halign: "right" },
          4: { cellWidth: 22, halign: "right" },
        },
        theme: "grid",
        margin: { left: 14, right: 14, top: 69 },
        // Hook para dibujar el encabezado en cada nueva página
        didDrawPage: (data: any) => {
          dibujarEncabezadoEnvio(docEnvio);
        },
      });

      const finalYEnvio = (docEnvio as any).lastAutoTable?.finalY || 100;

      // Nota de tipo de entrega (solo en la última página)
      docEnvio.setFontSize(7);
      docEnvio.setFont("helvetica", "normal");
      if (enviarDomicilio) {
        docEnvio.text("TIPO DE ENTREGA: A DOMICILIO", 14, finalYEnvio + 8);
      } else if (recogerLocal) {
        docEnvio.text("TIPO DE ENTREGA: RECOGER EN LOCAL", 14, finalYEnvio + 8);
      }

      // Verificar espacio disponible en la página
      const pageHeight = docEnvio.internal.pageSize.height;
      const espacioNecesario = 60; // QR (40) + texto (8) + margen (12)
      const espacioDisponible = pageHeight - finalYEnvio - 20;

      // Si no hay espacio suficiente, agregar nueva página
      let yBase: number;
      if (espacioDisponible < espacioNecesario) {
        docEnvio.addPage();
        dibujarEncabezadoEnvio(docEnvio); // Usar la función correcta según tu código
        yBase = 70; // Empezar después del encabezado
      } else {
        yBase = finalYEnvio + 18;
      }

     
      // TOTALES DEL LADO DERECHO 
      docEnvio.setFontSize(8);
      docEnvio.setFont("helvetica", "bold");
      docEnvio.setTextColor(0, 0, 0);

      // Línea separadora
      docEnvio.setLineWidth(0.5);
      docEnvio.line(145, yBase, 196, yBase);

      // TOTAL NETO
      docEnvio.setFontSize(9);
      docEnvio.text("TOTAL NETO:", 145, yBase + 8);
      docEnvio.text(
        `$ ${totalConIVA.toLocaleString("en-US", {
          minimumFractionDigits: 2,
          maximumFractionDigits: 2,
        })}`,
        195,
        yBase + 8,
        { align: "right" },
      );

      // Pie de página con fecha/hora y número de página
      const pageCount2 = (docEnvio as any).getNumberOfPages();
      for (let i = 1; i <= pageCount2; i++) {
        docEnvio.setPage(i);
        const pageHeight = docEnvio.internal.pageSize.height;
        docEnvio.setFontSize(7);
        docEnvio.text(`Página ${i} de ${pageCount2}`, 14, pageHeight - 8);
        docEnvio.text(`${fecha} ${hora}`, 160, pageHeight - 8);
      }
      {
        /*
      // Enviar PDF por correo
      const pdfBase64 = docEnvio.output("datauristring");
      await fetch("/api/enviar-pedido", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          pdfBase64,
          correoDestino: "bfmpedidos@gmail.com",
        }),
      });
*/
      }
      // PDF PARA CLIENTE (docCliente)
      const docCliente = new jsPDF();

      // Tabla
      autoTableModule.default(docCliente, {
          head: [["CÓDIGO", "CANT", "UNIDAD", "DESCRIPCIÓN", "P. UNIT.", "IMPORTE"]],
  body: productosTablaCliente,
        startY: 69,
        styles: {
          fontSize: 7,
          cellPadding: 1.5,
          lineColor: [180, 180, 180],
          lineWidth: 0.1,
          textColor: [0, 0, 0],
        },
        headStyles: {
          fillColor: [230, 230, 230],
          textColor: [0, 0, 0],
          fontStyle: "bold",
          halign: "center",
          fontSize: 7,
        },
        columnStyles: {
          0: { cellWidth: 28, halign: "center" },
    1: { cellWidth: 13, halign: "center" },
    2: { cellWidth: 18, halign: "center" },
    3: { cellWidth: 77, halign: "left" },
    4: { cellWidth: 22, halign: "right" },
    5: { cellWidth: 22, halign: "right" },
        },
        theme: "grid",
        margin: { left: 14, right: 14, top: 69 },
        // Hook para dibujar el encabezado en cada nueva página
        didDrawPage: (data: any) => {
          dibujarEncabezadoCliente(docCliente);
        },
      });

      const finalYCliente = (docCliente as any).lastAutoTable?.finalY || 100;

      // Tipo de entrega (solo en la última página)
      docCliente.setFontSize(7);
      docCliente.setFont("helvetica", "normal");
      if (enviarDomicilio) {
        docCliente.text("TIPO DE ENTREGA: A DOMICILIO", 14, finalYCliente + 8);
      } else if (recogerLocal) {
        docCliente.text(
          "TIPO DE ENTREGA: RECOGER EN LOCAL",
          14,
          finalYCliente + 8,
        );
      }

      // Verificar espacio disponible en la página
      const pageHeightCliente = docCliente.internal.pageSize.height;
      const espacioNecesarioCliente = 60;
      const espacioDisponibleCliente = pageHeightCliente - finalYCliente - 20;

      // Si no hay espacio suficiente, agregar nueva página
      let yBaseCliente: number;
      if (espacioDisponibleCliente < espacioNecesarioCliente) {
        docCliente.addPage();
        dibujarEncabezadoCliente(docCliente);
        yBaseCliente = 70;
      } else {
        yBaseCliente = finalYCliente + 18;
      }

     
      // TOTALES DEL LADO DERECHO 
      docCliente.setFontSize(8);
      docCliente.setFont("helvetica", "bold");
      docCliente.setTextColor(0, 0, 0);

      // Línea separadora
      docCliente.setLineWidth(0.5);
      docCliente.line(145, yBaseCliente, 196, yBaseCliente);

      // TOTAL NETO
      docCliente.setFontSize(9);
      docCliente.text("TOTAL NETO:", 145, yBaseCliente + 8);
      docCliente.text(
        `$ ${totalConIVA.toLocaleString("en-US", {
          minimumFractionDigits: 2,
          maximumFractionDigits: 2,
        })}`,
        195,
        yBaseCliente + 8,
        { align: "right" },
      );

      // Pie de página
      const pageCount = (docCliente as any).getNumberOfPages();
      for (let i = 1; i <= pageCount; i++) {
        docCliente.setPage(i);
        const pageHeight = docCliente.internal.pageSize.height;
        docCliente.setFontSize(7);
        docCliente.text(`Página ${i} de ${pageCount}`, 14, pageHeight - 8);
        docCliente.text(`${fecha} ${hora}`, 160, pageHeight - 8);
      }

      // Guardar PDF en Supabase Storage
      const pdfBlob = docCliente.output("blob");
      const nombreArchivoPDF = `pedido_${pedidoId}_${Date.now()}.pdf`;

      const { data: uploadData, error: uploadError } = await supabase.storage
        .from("pedidos-pdf")
        .upload(nombreArchivoPDF, pdfBlob, {
          contentType: "application/pdf",
          cacheControl: "public, max-age=31536000",
          upsert: true,
        });

      if (uploadError) {
        console.error("Error subiendo PDF a Supabase:", uploadError);
      } else {
        console.log("PDF subido correctamente");

        // Obtener URL pública del PDF
        const {
          data: { publicUrl },
        } = supabase.storage.from("pedidos-pdf").getPublicUrl(nombreArchivoPDF);

        // Actualizar el pedido con la URL del PDF
        const { error: updateError } = await supabase
          .from("pedidos")
          .update({ pdf_url: publicUrl })
          .eq("id", pedidoId);

        if (updateError) {
          console.error("Error actualizando URL del PDF:", updateError);
        }
      }

      // Descargar PDF localmente para el cliente
      {
        /*  
    const nombreArchivo = `Pedido_${cliente.replace(/\s+/g, "_")}.pdf`;
    docCliente.save(nombreArchivo);
     */
      }

      setMensajeExito("Su pedido ha sido enviado con éxito.");
      setMostrarModalPedido(false);
      setCarrito([]);
      setMostrarExito(true);
    } catch (error) {
      console.error("Error al enviar pedido:", error);
      setMensajeExito(
        "Ocurrió un error al enviar el pedido. Intente nuevamente.",
      );
    } finally {
      setEnviando(false);
      setEnviarDomicilio(false);
      setRecogerLocal(false);
    }
  };

